import { Card, CardContent, Divider, IconButton, useMediaQuery } from "@mui/material";
import Box from "@mui/material/Box";
import Container from "@mui/material/Container";
import Grid from "@mui/material/Grid";
import Typography from "@mui/material/Typography";
import { useTheme } from '@mui/material/styles';
import { navigate } from "gatsby";
import React, { useEffect, useState } from "react";
import ButtonInput from "../components/ButtonInput/ButtonInput";
import CustomButton from "../components/CustomButton/CustomButton";
import Layout from "../components/Layout";
import QuantityInput from "../components/QuantityInput/QuantityInput";
import { ICartRes, IStock } from "../types/types";
import { formatCep, formatCoupon, formatMoney } from "../utils/utils";
import useUser from "../storage/useUser";
import useSettings from "../storage/useSettings";
import useCart from "../storage/useCart";
import { Delete as DeleteIcon } from "@mui/icons-material";
import api, { URL_BACK } from "../components/api";
import ShippingCard from "../components/ShippingCard";
import useAdress from "../storage/useAddress";

const debugColors = ['white', 'white', 'white', 'white', 'white', 'white', 'white', 'white']
// const debugColors = ['red', 'green', 'pink', 'blue', 'gray', 'lightBlue', 'orange', 'yellow']

export default function Carrinho() {
    const theme = useTheme();
    const isMediumScreen = useMediaQuery(theme.breakpoints.up('md'));
    const { stocks } = useSettings();
    const { items, updateQuantity, removeItemFromCart } = useCart();
    const { cacheAddress, searchCepAndStoreLocal } = useAdress();
    const initialCep = (cacheAddress && cacheAddress.cep) ? formatCep(cacheAddress.cep) : '';
    const [cep, setCep] = useState<string>(initialCep);
    const [coupon, setCoupon] = useState<string>('');
    const [cartRes, setCartRes] = useState<ICartRes>();
    const { isLogged } = useUser();

    const handleSearchCep = () => {
        searchCepAndStoreLocal(cep);
    }

    const handleNext = () => {
        if (isLogged()) {
            navigate('/checkout');
        } else {
            navigate('/login');
        }
    }

    const callCartApi = () => {
        api.post("/v1/cart", {
            buy: {
                items: items.map((i) => ({
                    productId: i.productId,
                    stockId: i.stockId,
                    quantity: i.quantity
                })),
                coupon: coupon || null,
                address: {
                    zipcode: cacheAddress?.cep || null,
                    state: cacheAddress?.state || null,
                    city: cacheAddress?.city || null
                }
            }
        }).then((res) => {
            setCartRes(res.data);
        }).catch((e) => {
            console.log(e);
            alert('Houve um erro, tente mais tarde.')
        });
    }

    const getStockById = (id: number): IStock | undefined => {
        return stocks.find((s) => s.id === id);
    }

    useEffect(() => {
        if (items?.length)
            callCartApi()
    }, [cacheAddress]);


    return (
        <Layout hideFooter={true}>
            {(!items || items.length === 0) ?
                <Container
                    sx={{
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        height: '50vh',
                    }}
                >
                    <Typography variant="h5" mb={4}>
                        Seu carrinho está vazio
                    </Typography>
                    <CustomButton title="Ir às compras" onClick={() => navigate('/')} width="50%" />
                </Container>
                :
                <Container>

                    <Typography variant="h4" gutterBottom mt={4}>
                        Carrinho
                    </Typography>
                    <Card>

                        <Grid container>

                            <Grid item xs={12} md={8} bgcolor={debugColors[0]}>
                                <CardContent>
                                    {items.map((cartItem) => (
                                        <Box key={`${cartItem.productId}-${cartItem.stockId}`} style={{ display: 'flex' }} height={isMediumScreen ? 120 : 180} mt={4}>
                                            <Box bgcolor={debugColors[1]} width={isMediumScreen ? 100 : 70} >
                                                <img width={isMediumScreen ? 100 : 70} src={URL_BACK + "/" + cartItem.picture} />
                                            </Box>
                                            <Box bgcolor={debugColors[2]} width={668}>
                                                <Typography variant="subtitle2" pl={1}>
                                                    {cartItem.name.length <= 50 ? cartItem.name : cartItem.name.substring(0, 50) + "..."}
                                                </Typography>
                                                <Grid container height={120}>
                                                    <Grid item xs={12} md={6} bgcolor={debugColors[3]}>
                                                        <Box sx={{ display: 'flex', justifyContent: 'space-between' }}>
                                                            <Box ml={1}>
                                                                <Typography variant="body2" color="text.secondary">
                                                                    Cor: {getStockById(cartItem.stockId)?.colorName}
                                                                </Typography>
                                                                <Typography variant="body2" color="text.secondary">
                                                                    Tamanho: {getStockById(cartItem.stockId)?.sizeName}
                                                                </Typography>
                                                            </Box>
                                                        </Box>
                                                    </Grid>
                                                    <Grid item xs={12} md={3} bgcolor={debugColors[4]} pl={1}>
                                                        <QuantityInput
                                                            value={cartItem.quantity}
                                                            onChange={(qtd) => updateQuantity(cartItem.productId, cartItem.stockId, qtd)}
                                                            min={1}
                                                            max={99}
                                                            onMin={() => alert("TODO: Deseja excluir?")}
                                                        />
                                                    </Grid>
                                                    <Grid item xs={9} md={2} bgcolor={debugColors[5]} pl={1} pt="4px">
                                                        <Typography variant="subtitle1" color="text.secondary">
                                                            {formatMoney(cartItem.unitPrice * cartItem.quantity)}
                                                        </Typography>
                                                    </Grid>
                                                    <Grid item xs={1} md={1} bgcolor={debugColors[6]} pl={1}>
                                                        {/* TODO: colocar confirmação para deletar aqui */}
                                                        <IconButton size="small" onClick={() => removeItemFromCart(cartItem.productId, cartItem.stockId)}>
                                                            <DeleteIcon />
                                                        </IconButton>
                                                    </Grid>
                                                </Grid>
                                            </Box>
                                        </Box>
                                    ))}
                                </CardContent>

                            </Grid>

                            <Grid item xs={12} md={4} bgcolor='#f8f4f4' p={2}>
                                <Box>
                                    <Typography variant="h6">
                                        Entrega
                                    </Typography>
                                    <ButtonInput
                                        value={cep}
                                        onChange={setCep}
                                        onClick={handleSearchCep}
                                        mask={formatCep}
                                        label='INFORME O CEP'
                                        buttonLabel='Calcular'
                                        width='100%'
                                    />
                                    <Box mt={2}>
                                        <ShippingCard
                                            isLoadingCep={false}
                                            bgColor={'#f8f4f4'}
                                        />
                                    </Box>
                                </Box>
                                <Box mt={3} sx={!isMediumScreen ? { pb: 8 } : null}>
                                    <Typography variant="h6">
                                        Cupom
                                    </Typography>
                                    <ButtonInput
                                        value={coupon}
                                        onChange={setCoupon}
                                        mask={formatCoupon}
                                        onClick={() => callCartApi()}
                                        label='INSIRA O CUPOM'
                                        buttonLabel='APLICAR'
                                        width='100%'
                                    />
                                    {!!(cartRes?.couponValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Cupom: {cartRes.couponValue}
                                        </Typography>
                                    }
                                    {!!(cartRes?.deliveryValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Frete: {cartRes.deliveryValue}
                                        </Typography>
                                    }
                                    {!!(cartRes?.productsValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Subtotal: {cartRes.productsValue}
                                        </Typography>
                                    }

                                    {!!(cartRes?.totalValue) &&
                                        <Typography variant="subtitle1" color="text.secondary">
                                            Total: {cartRes.totalValue}
                                        </Typography>
                                    }
                                </Box>
                                <Box mt={4} sx={!isMediumScreen ? { width: '100%', position: 'fixed', bottom: 0, left: 0 } : null}>
                                    <CustomButton title="Avançar" onClick={handleNext} width="100%" />
                                </Box>
                            </Grid>
                        </Grid>
                    </Card>
                </Container>
            }
        </Layout >
    );
}
